function calcularDVRut(value) {

  const rut = value.RUT;
    console.log("rut:",rut);
  if (!rut) return null;
  const clean = String(rut).replace(/[\.\-\/\s]/g, '').replace(/^0+/, '');
  if (!/^\d+$/.test(clean)) return null;

  let sum = 0;
  let multip = 2;
  for (let i = clean.length - 1; i >= 0; i--) {
    sum += parseInt(clean.charAt(i), 10) * multip;
    multip = multip === 7 ? 2 : multip + 1;
  }

  const remainder = sum % 11;
  const dvNumeric = 11 - remainder;
  if (dvNumeric === 11) return '0';
  if (dvNumeric === 10) return 'K';
  return String(dvNumeric);
}

// Si recibes el rut desde otro nodo (por ejemplo un input)
const rut = query || '15670326';

// Calcular el DV y devolver el resultado al flujo
const dv = calcularDVRut(rut);

// Resultado que n8n podrá usar en los siguientes nodos
return dv;

